exemplos.python:
def somar_itens(*valores):
    total = 0.0
    for valor in valores:
        total += valor
    return total

print(somar_itens(10.0, 20.0, 30.0))

def totalizar(*valores, **config):
    total = sum(valores)
    taxa = config.get('taxa', 0.0)
    return total * (1 + taxa)

print(f'Total: {totalizar(100, 200, taxa=0.1):.2f}')

pratica_guiada.python:
def somar_repasses(*valores):
    total = 0.0
    for valor in valores:
        total += valor
    return total

def resumo_meta(valor_atual, meta, **config):
    mostrar_percentual = config.get('percentual', False)
    if mostrar_percentual:
        taxa = (valor_atual / meta) * 100
        return f'Status: {valor_atual:.2f}/{meta:.2f} ({taxa:.1f}%)'
    return f'Status: {valor_atual:.2f}/{meta:.2f}'

print(f'Total: R$ {somar_repasses(100.0, 200.0, 50.0):.2f}')
print(resumo_meta(90.0, 100.0, percentual=True))
